function current_language($user = null) {
    $lang = $_GET['lang'] ?? null;
    if (!$lang && $user && isset($user['settings'])) {
        $settings = json_decode($user['settings'] ?? '{}', true);
        if (is_array($settings)) $lang = $settings['language'] ?? null;
    }
    if (!$lang) $lang = $_SESSION['language'] ?? 'fr';
    if (!isset(SUPPORTED_LANGUAGES[$lang])) $lang = 'fr';
    $_SESSION['language'] = $lang;
    return $lang;
}

function t($key, $lang = null) {
    $lang = $lang ?: ($_SESSION['language'] ?? 'fr');
    $dict = i18n_extend_base($lang);
    return $dict[$key] ?? I18N['fr'][$key] ?? $key;
}
